const MQL5 = {
  generate(bot) {
    const c = bot.configuration;
    return `//+------------------------------------------------------------------+
//| ${bot.name}.mq5                                                   |
//| Generated by BotForge                                              |
//+------------------------------------------------------------------+

#property description "${bot.name} - ${c.strategy} strategy"
#property version   "1.00"

// --- Input Parameters ---
input double RiskPerTrade      = ${c.moneyManagement.riskPerTrade};
input double MaxDailyLoss      = ${c.moneyManagement.maxDailyLoss};
input double MaxDailyProfit    = ${c.moneyManagement.maxDailyProfit};
input double FixedLotSize      = ${c.moneyManagement.lotSize};
input int    StopLoss          = ${c.tradeManagement.stopLoss};
input int    TakeProfit        = ${c.tradeManagement.takeProfit};
input bool   UseTrailing       = ${c.tradeManagement.trailingStop.enabled};
input int    TrailingPoints    = ${c.tradeManagement.trailingStop.points};
input string TradingSymbol     = "${c.symbol}";
input ulong  MagicNumber       = 202401;

// --- Trade globals ---
CTrade   Trade;
CPositionInfo PositionInfo;
COrderInfo   OrderInfo;
CSymbolInfo  SymbolInfo;
CTerminalInfo TerminalInfo;

double g_dailyProfit = 0;
double g_dailyLoss   = 0;
datetime g_lastBar   = 0;

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit() {
   Trade.SetExpertMagicNumber(MagicNumber);
   Trade.SetDeviationInPoints(10);

   SymbolInfo.Name(Symbol());
   SymbolInfo.Refresh();

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason) {
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick() {
   if (!IsNewBar()) return;

   UpdateDailyPL();

   if (g_dailyLoss >= MaxDailyLoss || g_dailyProfit >= MaxDailyProfit) {
      Comment("Daily limit reached");
      return;
   }

   ${this.generateStrategy(c)}
}

//+------------------------------------------------------------------+
//| Strategy Implementation                                          |
//+------------------------------------------------------------------+
${this.getStrategyFunctions(c)}

//+------------------------------------------------------------------+
//| Helper: Check if new bar                                         |
//+------------------------------------------------------------------+
bool IsNewBar() {
   datetime curBar = iTime(Symbol(), PERIOD_CURRENT, 0);
   if (g_lastBar != curBar) {
      g_lastBar = curBar;
      return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Helper: Update daily profit/loss                                 |
//+------------------------------------------------------------------+
void UpdateDailyPL() {
   g_dailyProfit = 0;
   g_dailyLoss   = 0;
   for (int i = PositionsTotal() - 1; i >= 0; i--) {
      if (PositionSelectByTicket(PositionGetTicket(i))) {
         if (PositionGetInteger(POSITION_MAGIC) == (long)MagicNumber) {
            double profit = PositionGetDouble(POSITION_PROFIT);
            if (profit > 0) g_dailyProfit += profit;
            else g_dailyLoss += MathAbs(profit);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Helper: Calculate lot size                                       |
//+------------------------------------------------------------------+
double CalculateLot() {
   double lot = FixedLotSize;
   double minLot = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MIN);
   double maxLot = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX);
   double step  = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_STEP);
   lot = fmax(minLot, fmin(maxLot, lot));
   lot = MathRound(lot / step) * step;
   return lot;
}

//+------------------------------------------------------------------+
//| Helper: Send order                                               |
//+------------------------------------------------------------------+
bool SendOrder(int type, double lot, double sl, double tp, string comment) {
   double price = (type == ORDER_TYPE_BUY) ? SymbolInfoDouble(Symbol(), SYMBOL_ASK) :
                                              SymbolInfoDouble(Symbol(), SYMBOL_BID);
   double slPrice = (type == ORDER_TYPE_BUY) ? price - sl * Point() : price + sl * Point();
   double tpPrice = (type == ORDER_TYPE_BUY) ? price + tp * Point() : price - tp * Point();

   Trade.PositionOpen(Symbol(), type, lot, price, slPrice, tpPrice, comment);
   return Trade.ResultRetcode() == TRADE_RETCODE_DONE;
}
`;
  },

  generateStrategy(config) {
    switch (config.strategy) {
      case 'grid': return this.gridEntry(config);
      case 'martingale': return this.martingaleEntry(config);
      case 'hedging': return this.hedgingEntry(config);
      case 'trend': return this.trendEntry(config);
      case 'scalping': return this.scalpingEntry(config);
      default: return this.gridEntry(config);
    }
  },

  getStrategyFunctions(config) {
    switch (config.strategy) {
      case 'grid': return this.gridFunctions();
      case 'martingale': return this.martingaleFunctions();
      case 'hedging': return this.hedgingFunctions();
      case 'trend': return this.trendFunctions();
      case 'scalping': return this.scalpingFunctions();
      default: return this.gridFunctions();
    }
  },

  gridEntry(config) {
    return `
   // Grid Trading Entry
   int gridLevels = ${config.grid.gridLevels};
   int posCount = CountOpenPositions();

   if (posCount < gridLevels) {
      double lot = CalculateLot();
      SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Grid Buy");
      SendOrder(ORDER_TYPE_SELL, lot, StopLoss, TakeProfit, "Grid Sell");
   }
`;
  },

  gridFunctions() {
    return `
//+------------------------------------------------------------------+
//| Count open positions                                             |
//+------------------------------------------------------------------+
int CountOpenPositions() {
   int count = 0;
   for (int i = PositionsTotal() - 1; i >= 0; i--) {
      if (PositionSelectByTicket(PositionGetTicket(i))) {
         if (PositionGetInteger(POSITION_MAGIC) == (long)MagicNumber)
            count++;
      }
   }
   return count;
}
`;
  },

  martingaleEntry(config) {
    return `
   // Martingale Entry
   double lot = CalculateLot();
   int posCount = CountOpenPositions();

   if (posCount == 0) {
      SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Martingale");
   } else {
      ulong lastTicket = GetLastTicket();
      if (lastTicket > 0 && PositionSelectByTicket(lastTicket)) {
         if (PositionGetDouble(POSITION_PROFIT) < 0) {
            lot = NormalizeDouble(lot * ${config.moneyManagement.martingaleMultiplier}, 2);
            double maxLot = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX);
            lot = fmin(lot, maxLot);
            SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Martingale");
         }
      }
   }
`;
  },

  martingaleFunctions() {
    return `
//+------------------------------------------------------------------+
//| Get last position ticket                                         |
//+------------------------------------------------------------------+
ulong GetLastTicket() {
   ulong ticket = 0;
   datetime t = 0;
   for (int i = PositionsTotal() - 1; i >= 0; i--) {
      ulong posTicket = PositionGetTicket(i);
      if (PositionSelectByTicket(posTicket)) {
         if (PositionGetInteger(POSITION_MAGIC) == (long)MagicNumber) {
            datetime ot = (datetime)PositionGetInteger(POSITION_TIME);
            if (ot > t) { t = ot; ticket = posTicket; }
         }
      }
   }
   return ticket;
}
`;
  },

  hedgingEntry(config) {
    return `
   // Hedging Entry
   double lot = CalculateLot();
   int buyCount = CountOrdersByType(ORDER_TYPE_BUY);
   int sellCount = CountOrdersByType(ORDER_TYPE_SELL);

   if (buyCount == 0 && sellCount == 0) {
      SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Hedge Buy");
   }
   if (buyCount > 0 && sellCount == 0) {
      SendOrder(ORDER_TYPE_SELL, lot, StopLoss, TakeProfit, "Hedge Sell");
   }
   if (sellCount > 0 && buyCount == 0) {
      SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Hedge Buy");
   }
`;
  },

  hedgingFunctions() {
    return `
//+------------------------------------------------------------------+
//| Count positions by type                                          |
//+------------------------------------------------------------------+
int CountOrdersByType(ENUM_ORDER_TYPE type) {
   int count = 0;
   for (int i = PositionsTotal() - 1; i >= 0; i--) {
      ulong ticket = PositionGetTicket(i);
      if (PositionSelectByTicket(ticket)) {
         if (PositionGetInteger(POSITION_MAGIC) == (long)MagicNumber &&
             (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE) == type)
            count++;
      }
   }
   return count;
}
`;
  },

  trendEntry(config) {
    return `
   // Trend Following Entry
   double lot = CalculateLot();
   if (CountOpenPositions() > 0) return;

   double maFast   = iMA(Symbol(), PERIOD_CURRENT, 10, 0, MODE_EMA, PRICE_CLOSE, 1);
   double maSlow   = iMA(Symbol(), PERIOD_CURRENT, 30, 0, MODE_EMA, PRICE_CLOSE, 1);
   double maFastPrev = iMA(Symbol(), PERIOD_CURRENT, 10, 0, MODE_EMA, PRICE_CLOSE, 2);
   double maSlowPrev = iMA(Symbol(), PERIOD_CURRENT, 30, 0, MODE_EMA, PRICE_CLOSE, 2);

   if (maFastPrev <= maSlowPrev && maFast > maSlow) {
      SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Trend Buy");
   }
   if (maFastPrev >= maSlowPrev && maFast < maSlow) {
      SendOrder(ORDER_TYPE_SELL, lot, StopLoss, TakeProfit, "Trend Sell");
   }
`;
  },

  trendFunctions() {
    return `// (uses CountOpenPositions from Grid strategy)`;
  },

  scalpingEntry(config) {
    return `
   // Scalping Entry
   double lot = CalculateLot();
   if (CountOpenPositions() > 3) return;

   double rsi = iRSI(Symbol(), PERIOD_M5, 14, PRICE_CLOSE, 0);

   if (rsi < 30) {
      SendOrder(ORDER_TYPE_BUY, lot, StopLoss, TakeProfit, "Scalp Buy");
   }
   if (rsi > 70) {
      SendOrder(ORDER_TYPE_SELL, lot, StopLoss, TakeProfit, "Scalp Sell");
   }
`;
  },

  scalpingFunctions() {
    return `// (uses CountOpenPositions from Grid strategy)`;
  }
};